\subsection{Comparison-iso typeclass carrier (iter-050)}

The iter-048 carrier $\Scheme.\IsCechAcyclicCover$ packages \emph{Čech-side} positive-degree vanishing as a $\Prop$-class. Its consumer $\mathtt{subsingleton\_HModule}'\_\mathtt{supr\_of\_isCechAcyclicCover}$ — and the iter-049 universe-$u+1$ companion $\mathtt{subsingleton\_HModule\_of\_isCechAcyclicCover\_top}$ — both take the comparison iso $\mathtt{compIso} : \forall n,\ \cechCohomology\,n \equiv_k \HModulePrime\,n\,(\bigsqcup\mathcal U)$ as an \emph{explicit} argument. This forces every call site to either receive the iso as a hypothesis or to construct it from a substantive comparison theorem (queued for iter-051+). Iter-050 packages the iso as a \emph{typeclass} hypothesis — a Prop-class $\Scheme.\HasCechToHModuleIso$ wrapping $\mathtt{Nonempty}\,(\forall n,\ \cechCohomology\,n \equiv_k \HModulePrime\,n\,(\bigsqcup\mathcal U))$ — together with a $\noncomputable$ $\Classical.\mathtt{choice}$-based extractor and instance-driven consumers chaining iter-049. The decoupling lets the iter-052+ producer chain (basic-open cover acyclicity + Čech-vs-derived comparison theorem) saturate via typeclass synthesis without re-passing the iso explicitly at every call site, mirroring how iter-046's $\IsHModuleHomFinite$ instance is consumed by iter-038/039 transports.

\begin{definition}\leanok
[Comparison-iso typeclass carrier, iter-050]
  \label{def:Scheme_HasCechToHModuleIso}
  \lean{AlgebraicGeometry.Scheme.HasCechToHModuleIso}
  \uses{def:Scheme_cechCohomology, def:Scheme_HModule_prime}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathtt{of}\,k))$, $F$ a sheaf of $\ModuleCat\,k$-modules on $\Opens\,C.\mathtt{left}.\mathtt{toTopCat}$, and $\mathcal U : \iota \to \Opens\,C.\mathtt{left}.\mathtt{toTopCat}$ a cover. Assume $\HasExt_u$ on $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$. The cover \emph{has the Čech-vs-derived comparison iso for $F$} iff there exists, for every $n \in \mathbb N$, a $k$-linear isomorphism between $\cechCohomology\,C\,F\,\mathcal U\,n$ and $\HModulePrime\,k\,F\,n\,(\bigsqcup_i \mathcal U_i)$. Packaged as a $\Prop$-valued class with single field $\mathtt{nonempty\_compIso} : \mathtt{Nonempty}\,(\forall n,\ \ldots)$.
\end{definition}

\begin{theorem}\leanok
[Comparison-iso extractor, iter-050]
  \label{def:Scheme_cechToHModuleIso}
  \lean{AlgebraicGeometry.Scheme.cechToHModuleIso}
  \uses{def:Scheme_HasCechToHModuleIso, def:Scheme_cechCohomology, def:Scheme_HModule_prime}
  Under the iter-050 typeclass hypothesis $[\HasCechToHModuleIso\,F\,\mathcal U]$, the comparison iso $\forall n,\ \cechCohomology\,C\,F\,\mathcal U\,n \equiv_k \HModulePrime\,k\,F\,n\,(\bigsqcup_i \mathcal U_i)$ exists (as data) via $\Classical.\mathtt{choice}$ on the class field $\mathtt{nonempty\_compIso}$.
\end{theorem}

\begin{proof}\leanok
  Direct application of $\Classical.\mathtt{choice}$ to $\HasCechToHModuleIso.\mathtt{nonempty\_compIso}$. Plan-agent $\mathtt{lean\_run\_code}$ probe (iter-050 pass) confirms kernel-only axioms $[\propext, \mathtt{Classical.choice}, \mathtt{Quot.sound}]$ — $\Classical.\mathtt{choice}$ is already in the kernel-only set, no new axiom introduced.
\end{proof}

\begin{theorem}\leanok
[Instance-driven top-supremum HModule transport, abstract sheaf form, iter-050]
  \label{thm:Scheme_subsingleton_HModule_of_hasCechToHModuleIso_top}
  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule_of_hasCechToHModuleIso_top}
  \uses{def:Scheme_HasCechToHModuleIso, def:Scheme_cechToHModuleIso, thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathtt{of}\,k))$, $F$ a sheaf of $\ModuleCat\,k$-modules on $\Opens\,C.\mathtt{left}.\mathtt{toTopCat}$. Assume $\HasExt_u$ and $\HasExt_{u+1}$ on the same sheaf category. Let $\mathcal U : \iota \to \Opens\,C.\mathtt{left}.\mathtt{toTopCat}$ with both $[\IsCechAcyclicCover\,F\,\mathcal U]$ and $[\HasCechToHModuleIso\,F\,\mathcal U]$, and $\bigsqcup_i \mathcal U_i = \top$. For $n \geq 1$, the underlying type of $\HModule\,k\,F\,n$ is a subsingleton.
\end{theorem}

\begin{proof}\leanok
  Direct application of Theorem~\ref{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top} to the explicitly extracted comparison iso $\Scheme.\cechToHModuleIso$ (Theorem~\ref{def:Scheme_cechToHModuleIso}) — typeclass synthesis fires automatically on the $[\HasCechToHModuleIso]$ instance argument, recovering the $\forall n,\ \mathtt{compIso}_n$ functional. Plan-agent $\mathtt{lean\_run\_code}$ probe (iter-050 pass) confirms kernel-only axioms.
\end{proof}

\begin{theorem}\leanok
[Instance-driven top-supremum HModule transport, curve form, iter-050]
  \label{thm:Scheme_subsingleton_HModule_of_hasCechToHModuleIso_top_curve}
  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule_of_hasCechToHModuleIso_top_curve}
  \uses{thm:Scheme_subsingleton_HModule_of_hasCechToHModuleIso_top, def:Scheme_toModuleKSheaf}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathtt{of}\,k))$. Assume $\HasExt_u$ and $\HasExt_{u+1}$. Let $\mathcal U : \iota \to \Opens\,C.\mathtt{left}.\mathtt{toTopCat}$ with $[\IsCechAcyclicCover\,(\Scheme.\toModuleKSheaf\,C)\,\mathcal U]$ and $[\HasCechToHModuleIso\,(\Scheme.\toModuleKSheaf\,C)\,\mathcal U]$, and $\bigsqcup_i \mathcal U_i = \top$. For $n \geq 1$, the underlying type of $\HModule\,k\,(\Scheme.\toModuleKSheaf\,C)\,n$ is a subsingleton.
\end{theorem}

\begin{proof}\leanok
  Direct application of Theorem~\ref{thm:Scheme_subsingleton_HModule_of_hasCechToHModuleIso_top} to $F := \Scheme.\toModuleKSheaf\,C$ via the named-argument syntax. Plan-agent $\mathtt{lean\_run\_code}$ probe (iter-050 pass) confirms kernel-only axioms.
\end{proof}

\subsection{Use in Serre finiteness}
